import pytest
from fizzbuzz import fizzbuzz


# ---------------------------------------------------------------------------
# Happy path
# ---------------------------------------------------------------------------

class TestFizzBuzz:
    """Numbers divisible by both 3 and 5 (i.e. 15)."""

    def test_returns_fizzbuzz_for_15(self):
        assert fizzbuzz(15) == "FizzBuzz"

    def test_returns_fizzbuzz_for_30(self):
        assert fizzbuzz(30) == "FizzBuzz"

    def test_returns_fizzbuzz_for_45(self):
        assert fizzbuzz(45) == "FizzBuzz"


class TestFizz:
    """Numbers divisible by 3 but not 5."""

    def test_returns_fizz_for_3(self):
        assert fizzbuzz(3) == "Fizz"

    def test_returns_fizz_for_6(self):
        assert fizzbuzz(6) == "Fizz"

    def test_returns_fizz_for_9(self):
        assert fizzbuzz(9) == "Fizz"


class TestBuzz:
    """Numbers divisible by 5 but not 3."""

    def test_returns_buzz_for_5(self):
        assert fizzbuzz(5) == "Buzz"

    def test_returns_buzz_for_10(self):
        assert fizzbuzz(10) == "Buzz"

    def test_returns_buzz_for_25(self):
        assert fizzbuzz(25) == "Buzz"


class TestPlainNumber:
    """Numbers not divisible by 3 or 5."""

    def test_returns_string_for_1(self):
        assert fizzbuzz(1) == "1"

    def test_returns_string_for_2(self):
        assert fizzbuzz(2) == "2"

    def test_returns_string_for_7(self):
        assert fizzbuzz(7) == "7"

    def test_return_type_is_always_string(self):
        assert isinstance(fizzbuzz(1), str)
        assert isinstance(fizzbuzz(3), str)
        assert isinstance(fizzbuzz(5), str)
        assert isinstance(fizzbuzz(15), str)


