        """0 is divisible by every non-zero integer, so 0 % 15 == 0."""
        assert fizzbuzz(0) == "FizzBuzz"

    def test_negative_divisible_by_15(self):
        assert fizzbuzz(-15) == "FizzBuzz"

    def test_negative_divisible_by_3(self):
        assert fizzbuzz(-3) == "Fizz"

    def test_negative_divisible_by_5(self):
        assert fizzbuzz(-5) == "Buzz"

    def test_negative_plain_number(self):
        assert fizzbuzz(-1) == "-1"

